import uuid
import hashlib
import secrets
import time
from dataclasses import dataclass, field
from typing import Dict, Optional, List


@dataclass
class User:
    user_id: str
    username: str
    email: str
    password_hash: str
    full_name: str
    role: str = "user"
    created_at: float = field(default_factory=time.time)


@dataclass
class Session:
    token: str
    user_id: str
    username: str
    created_at: float
    expires_at: float


class UserDatabase:
    """In-memory user database for development. Replace with real DB in production."""

    def __init__(self):
        self.users: Dict[str, User] = {}
        self.username_index: Dict[str, str] = {}  # username -> user_id
        self.sessions: Dict[str, Session] = {}  # token -> Session

        # Seed with sample data
        self._seed_data()

    def _seed_data(self):
        """Add sample users for development."""
        sample_users = [
            ("admin", "admin@example.com", "admin123", "Admin User", "admin"),
            ("john_doe", "john@example.com", "password123", "John Doe", "user"),
            ("jane_smith", "jane@example.com", "password456", "Jane Smith", "user"),
            ("bob_wilson", "bob@example.com", "password789", "Bob Wilson", "moderator"),
        ]
        for username, email, password, full_name, role in sample_users:
            self.create_user(username, email, password, full_name, role)

    @staticmethod
    def _hash_password(password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()

    def create_user(
        self, username: str, email: str, password: str, full_name: str, role: str = "user"
    ) -> Optional[User]:
        if username in self.username_index:
            return None

        user_id = str(uuid.uuid4())
        user = User(
            user_id=user_id,
            username=username,
            email=email,
            password_hash=self._hash_password(password),
            full_name=full_name,
            role=role,
        )
        self.users[user_id] = user
        self.username_index[username] = user_id
        return user

    def authenticate(self, username: str, password: str) -> Optional[User]:
        user_id = self.username_index.get(username)
        if not user_id:
            return None
        user = self.users.get(user_id)
        if user and user.password_hash == self._hash_password(password):
            return user
        return None

    def create_session(self, user: User) -> Session:
        token = secrets.token_hex(32)
        session = Session(
            token=token,
            user_id=user.user_id,
            username=user.username,
            created_at=time.time(),
            expires_at=time.time() + 3600,  # 1 hour expiry
        )
        self.sessions[token] = session
        return session

    def validate_token(self, token: str) -> Optional[Session]:
        session = self.sessions.get(token)
        if session and session.expires_at > time.time():
            return session
        elif session:
            del self.sessions[token]
        return None

    def invalidate_token(self, token: str) -> bool:
        if token in self.sessions:
            del self.sessions[token]
            return True
        return False

    def get_user(self, user_id: str) -> Optional[User]:
        return self.users.get(user_id)

    def list_users(
        self, page: int = 1, page_size: int = 10, search_query: str = ""
    ) -> tuple[List[User], int]:
        all_users = list(self.users.values())

        if search_query:
            search_lower = search_query.lower()
            all_users = [
                u
                for u in all_users
                if search_lower in u.username.lower()
                or search_lower in u.full_name.lower()
                or search_lower in u.email.lower()
            ]

        total_count = len(all_users)
        start = (page - 1) * page_size
        end = start + page_size
        return all_users[start:end], total_count

    def update_user(
        self,
        user_id: str,
        email: Optional[str] = None,
        full_name: Optional[str] = None,
        role: Optional[str] = None,
    ) -> Optional[User]:
        user = self.users.get(user_id)
        if not user:
            return None
        if email:
            user.email = email
        if full_name:
            user.full_name = full_name
        if role:
            user.role = role
        return user

    def delete_user(self, user_id: str) -> bool:
        user = self.users.get(user_id)
        if not user:
            return False
        del self.username_index[user.username]
        del self.users[user_id]
        # Also invalidate any sessions for this user
        tokens_to_remove = [
            t for t, s in self.sessions.items() if s.user_id == user_id
        ]
        for token in tokens_to_remove:
            del self.sessions[token]
        return True


