# ============================================================
# Auth Service Implementation
# ============================================================


class AuthServiceServicer:
    """Implementation of the AuthService gRPC service."""

    def __init__(self, database: UserDatabase, pb2_module):
        self.db = database
        self.pb2 = pb2_module

    def Login(self, request, context):
        logger.info(f"Login attempt for user: {request.username}")

        user = self.db.authenticate(request.username, request.password)
        if not user:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Invalid username or password")
            return self.pb2.LoginResponse(
                success=False,
                token="",
                message="Invalid username or password",
            )

        session = self.db.create_session(user)
        user_info = self.pb2.UserInfo(
            user_id=user.user_id,
            username=user.username,
            email=user.email,
            full_name=user.full_name,
            role=user.role,
        )

        logger.info(f"User '{request.username}' logged in successfully")
        return self.pb2.LoginResponse(
            success=True,
            token=session.token,
            message="Login successful",
            user=user_info,
        )

    def Register(self, request, context):
        logger.info(f"Registration attempt for user: {request.username}")

        if not request.username or not request.email or not request.password:
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details("Username, email, and password are required")
            return self.pb2.RegisterResponse(
                success=False,
                message="Username, email, and password are required",
            )

        user = self.db.create_user(
            username=request.username,
            email=request.email,
            password=request.password,
            full_name=request.full_name,
        )

        if not user:
            context.set_code(grpc.StatusCode.ALREADY_EXISTS)
            context.set_details("Username already exists")
            return self.pb2.RegisterResponse(
                success=False,
                message="Username already exists",
            )

        logger.info(f"User '{request.username}' registered successfully with ID: {user.user_id}")
        return self.pb2.RegisterResponse(
            success=True,
            message="Registration successful",
            user_id=user.user_id,
        )

    def ValidateToken(self, request, context):
        logger.info("Token validation request received")

        session = self.db.validate_token(request.token)
        if not session:
            return self.pb2.TokenResponse(
                valid=False,
                user_id="",
                username="",
                expires_at=0,
            )

        return self.pb2.TokenResponse(
            valid=True,
            user_id=session.user_id,
            username=session.username,
            expires_at=int(session.expires_at),
        )

    def Logout(self, request, context):
        logger.info("Logout request received")

        success = self.db.invalidate_token(request.token)
        if success:
            return self.pb2.LogoutResponse(
                success=True,
                message="Logged out successfully",
            )
        else:
            return self.pb2.LogoutResponse(
                success=False,
                message="Invalid or expired token",
            )


