class DataServiceServicer:
    """Implementation of the DataService gRPC service."""

    def __init__(self, database: UserDatabase, pb2_module):
        self.db = database
        self.pb2 = pb2_module

    def _require_auth(self, context) -> Optional[Session]:
        """Extract and validate token from metadata."""
        metadata = dict(context.invocation_metadata())
        token = metadata.get("authorization", "")

        if token.startswith("Bearer "):
            token = token[7:]

        session = self.db.validate_token(token)
        if not session:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Valid authentication token required")
            return None
        return session

    def GetUser(self, request, context):
        logger.info(f"GetUser request for user_id: {request.user_id}")

        session = self._require_auth(context)
        if not session:
            return self.pb2.UserResponse(success=False, message="Unauthorized")

        user = self.db.get_user(request.user_id)
        if not user:
            context.set_code(grpc.StatusCode.NOT_FOUND)
            context.set_details(f"User {request.user_id} not found")
            return self.pb2.UserResponse(
                success=False,
                message=f"User {request.user_id} not found",
            )

        user_info = self.pb2.UserInfo(
            user_id=user.user_id,
            username=user.username,
            email=user.email,
            full_name=user.full_name,
            role=user.role,
        )

        return self.pb2.UserResponse(
            success=True,
            message="User found",
            user=user_info,
        )

    def ListUsers(self, request, context):
        logger.info(
            f"ListUsers request - page: {request.page}, page_size: {request.page_size}"
        )

        session = self._require_auth(context)
        if not session:
            return self.pb2.ListUsersResponse(success=False)

        page = max(1, request.page) if request.page else 1
        page_size = min(max(1, request.page_size), 100) if request.page_size else 10

        users, total_count = self.db.list_users(
            page=page,
            page_size=page_size,
            search_query=request.search_query,
        )

        user_infos = [
            self.pb2.UserInfo(
                user_id=u.user_id,
                username=u.username,
                email=u.email,
                full_name=u.full_name,
                role=u.role,
            )
            for u in users
        ]

        return self.pb2.ListUsersResponse(
            success=True,
            users=user_infos,
            total_count=total_count,
            page=page,
            page_size=page_size,
        )

    def UpdateUser(self, request, context):
        logger.info(f"UpdateUser request for user_id: {request.user_id}")

        session = self._require_auth(context)
        if not session:
            return self.pb2.UserResponse(success=False, message="Unauthorized")

        user = self.db.update_user(
            user_id=request.user_id,
            email=request.email or None,
            full_name=request.full_name or None,
            role=request.role or None,
        )

        if not user:
            context.set_code(grpc.StatusCode.NOT_FOUND)
            return self.pb2.UserResponse(
                success=False,
                message=f"User {request.user_id} not found",
            )

        user_info = self.pb2.UserInfo(
            user_id=user.user_id,
            username=user.username,
            email=user.email,
            full_name=user.full_name,
            role=user.role,
        )

        return self.pb2.UserResponse(
            success=True,
            message="User updated successfully",
            user=user_info,
        )

    def DeleteUser(self, request, context):
        logger.info(f"DeleteUser request for user_id: {request.user_id}")

        session = self._require_auth(context)
        if not session:
            return self.pb2.DeleteResponse(success=False, message="Unauthorized")

        # Check if requesting user is admin
        requesting_user = self.db.get_user(session.user_id)
        if not requesting_user or requesting_user.role != "admin":
            context.set_code(grpc.StatusCode.PERMISSION_DENIED)
            return self.pb2.DeleteResponse(
                success=False,
                message="Admin privileges required to delete users",
            )

        success = self.db.delete_user(request.user_id)
        if not success:
            context.set_code(grpc.StatusCode.NOT_FOUND)
            return self.pb2.DeleteResponse(
                success=False,
                message=f"User {request.user_id} not found",
            )

        return self.pb2.DeleteResponse(
            success=True,
            message="User deleted successfully",
        )

    def StreamUsers(self, request, context):
        """Server-streaming RPC - streams users one at a time."""
        logger.info("StreamUsers request received")

        session = self._require_auth(context)
        if not session:
            return

        page = max(1, request.page) if request.page else 1
        page_size = min(max(1, request.page_size), 100) if request.page_size else 10

        users, _ = self.db.list_users(
            page=page,
            page_size=page_size,
            search_query=request.search_query,
        )

        for user in users:
            if context.is_active():
                user_info = self.pb2.UserInfo(
                    user_id=user.user_id,
                    username=user.username,
                    email=user.email,
                    full_name=user.full_name,
                    role=user.role,
                )
                yield self.pb2.UserResponse(
                    success=True,
                    message="Streaming user data",
                    user=user_info,
                )
                time.sleep(0.1)  # Simulate processing delay
            else:
                break


