class LoggingInterceptor(grpc.ServerInterceptor):
    """Interceptor that logs all incoming RPC calls."""

    def intercept_service(self, continuation, handler_call_details):
        logger.info(
            f"Incoming RPC: {handler_call_details.method} "
            f"from metadata keys: {[m.key for m in (handler_call_details.invocation_metadata or [])]}"
        )
        return continuation(handler_call_details)


