# ============================================================
# Server Setup and Launch
# ============================================================


def create_server(
    port: int = 50051,
    max_workers: int = 10,
    database: Optional[UserDatabase] = None,
):
    """Create and configure the gRPC server."""

    pb2, pb2_grpc = _build_proto_module()

    if database is None:
        database = db

    # Create service instances
    auth_servicer = AuthServiceServicer(database, pb2)
    data_servicer = DataServiceServicer(database, pb2)

    # Create server with thread pool and interceptors
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        interceptors=[LoggingInterceptor()],
        options=[
            ("grpc.max_send_message_length", 50 * 1024 * 1024),  # 50MB
            ("grpc.max_receive_message_length", 50 * 1024 * 1024),  # 50MB
            ("grpc.keepalive_time_ms", 30000),
            ("grpc.keepalive_timeout_ms", 10000),
            ("grpc.keepalive_permit_without_calls", True),
        ],
    )

    # Register services
    pb2_grpc.add_AuthServiceServicer_to_server(auth_servicer, server)
    pb2_grpc.add_DataServiceServicer_to_server(data_servicer, server)

    # Bind to port (insecure for development)
    server.add_insecure_port(f"[::]:{port}")

    logger.info(f"Server configured on port {port} with {max_workers} workers")
    return server


def serve(port: int = 50051):
    """Start the gRPC server and handle graceful shutdown."""
    server = create_server(port=port)
    server.start()

    logger.info(f"=" * 60)
    logger.info(f"  gRPC Server started on port {port}")
    logger.info(f"  Services: AuthService, DataService")
    logger.info(f"  Mode: Development (insecure)")
    logger.info(f"=" * 60)

    # Graceful shutdown handler
    shutdown_event = threading.Event()

    def handle_shutdown(signum, frame):
        logger.info(f"Received signal {signum}, shutting down gracefully...")
        shutdown_event.set()
        server.stop(grace=5)  # 5 second grace period

    signal.signal(signal.SIGINT, handle_shutdown)
    signal.signal(signal.SIGTERM, handle_shutdown)

    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Server interrupted, shutting down...")
        server.stop(grace=5)

    logger.info("Server stopped.")


