class UserServiceClient:
    """
    gRPC client for the User microservice.
    Provides methods for authentication and data retrieval.
    """

    def __init__(self, host: str = "localhost", port: int = 50051):
        self.target = f"{host}:{port}"
        self.channel = None
        self.auth_stub = None
        self.data_stub = None
        self._token = None

        # Load proto modules
        self.pb2, self.pb2_grpc = _build_proto_module()

    def connect(self):
        """Establish connection to the gRPC server."""
        self.channel = grpc.insecure_channel(
            self.target,
            options=[
                ("grpc.max_send_message_length", 50 * 1024 * 1024),
                ("grpc.max_receive_message_length", 50 * 1024 * 1024),
                ("grpc.enable_retries", 1),
                ("grpc.keepalive_time_ms", 30000),
            ],
        )
        self.auth_stub = self.pb2_grpc.AuthServiceStub(self.channel)
        self.data_stub = self.pb2_grpc.DataServiceStub(self.channel)
        logger.info(f"Connected to gRPC server at {self.target}")
        return self

    def close(self):
        """Close the gRPC channel."""
        if self.channel:
            self.channel.close()
            logger.info("Connection closed")

    def __enter__(self):
        return self.connect()

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.close()

    def _get_auth_metadata(self):
        """Return authorization metadata for authenticated requests."""
        if self._token:
            return [("authorization", f"Bearer {self._token}")]
        return []

    # ---- Authentication Methods ----

    def login(self, username: str, password: str) -> dict:
        """Authenticate user and store token."""
        try:
            request = self.pb2.LoginRequest(username=username, password=password)
            response = self.auth_stub.Login(request, timeout=10)

            if response.success:
                self._token = response.token
                return {
                    "success": True,
                    "token": response.token,
                    "message": response.message,
                    "user": {
                        "user_id": response.user.user_id,
                        "username": response.user.username,
                        "email": response.user.email,
                        "full_name": response.user.full_name,
                        "role": response.user.role,
                    },
                }
            return {"success": False, "message": response.message}

        except grpc.RpcError as e:
            return {
                "success": False,
                "message": f"RPC Error: {e.code().name} - {e.details()}",
            }

    def register(
        self, username: str, email: str, password: str, full_name: str = ""
    ) -> dict:
        """Register a new user."""
        try:
            request = self.pb2.RegisterRequest(
                username=username,
                email=email,
                password=password,
                full_name=full_name,
            )
            response = self.auth_stub.Register(request, timeout=10)
            return {
                "success": response.success,
                "message": response.message,
                "user_id": response.user_id if response.success else None,
            }
        except grpc.RpcError as e:
            return {
                "success": False,
                "message": f"RPC Error: {e.code().name} - {e.details()}",
            }

    def validate_token(self, token: str = None) -> dict:
        """Validate an authentication token."""
        try:
            token = token or self._token
            if not token:
                return {"valid": False, "message": "No token provided"}

            request = self.pb2.TokenRequest(token=token)
            response = self.auth_stub.ValidateToken(request, timeout=10)
            return {
                "valid": response.valid,
                "user_id": response.user_id,
                "username": response.username,
                "expires_at": response.expires_at,
            }
        except grpc.RpcError as e:
            return {
                "valid": False,
                "message": f"RPC Error: {e.code().name} - {e.details()}",
            }

    def logout(self) -> dict:
        """Logout and invalidate current token."""
        try:
            if not self._token:
                return {"success": False, "message": "Not logged in"}

            request = self.pb2.LogoutRequest(token=self._token)
            response = self.auth_stub.Logout(request, timeout=10)

            if response.success:
                self._token = None

            return {"success": response.success, "message": response.message}
        except grpc.RpcError as e:
            return {
                "success": False,
                "message": f"RPC Error: {e.code().name} - {e.details()}",
            }

    # ---- Data Retrieval Methods ----

    def get_user(self, user_id: str) -> dict:
        """Get a user by ID."""
        try:
            request = self.pb2.GetUserRequest(user_id=user_id)
            response = self.data_stub.GetUser(
                request, metadata=self._get_auth_metadata(), timeout=10
            )

            if response.success:
                return {
                    "success": True,
                    "message": response.message,
                    "user": {
                        "user_id": response.user.user_id,
                        "username": response.user.username,
                        "email": response.user.email,
                        "full_name": response.user.full_name,
                        "role": response.user.role,
                    },
                }
            return {"success": False, "message": response.message}
        except grpc.RpcError as e:
            return {
                "success": False,
                "message": f"RPC Error: {e.code().name} - {e.details()}",
            }

    def list_users(
        self, page: int = 1, page_size: int = 10, search_query: str = ""
    ) -> dict:
        """List users with pagination and optional search."""
        try:
            request = self.pb2.ListUsersRequest(
                page=page, page_size=page_size, search_query=search_query
            )
            response = self.data_stub.ListUsers(
                request, metadata=self._get_auth_metadata(), timeout=10
            )

            if response.success:
                users = [
                    {
                        "user_id": u.user_id,
                        "username": u.username,
                        "email": u.email,
                        "full_name": u.full_name,
                        "role": u.role,
                    }
                    for u in response.users
                ]
                return {
                    "success": True,
                    "users": users,
                    "total_count": response.total_count,
                    "page": response.page,
                    "page_size": response.page_size,
                }
            return {"success": False, "users": []}
        except grpc.RpcError as e:
            return {
                "success": False,
                "message": f"RPC Error: {e.code().name} - {e.details()}",
                "users": [],
            }

    def update_user(
        self,
        user_id: str,
        email: str = "",
        full_name: str = "",
        role: str = "",
    ) -> dict:
        """Update a user's information."""
        try:
            request = self.pb2.UpdateUserRequest(
                user_id=user_id, email=email, full_name=full_name, role=role
            )
            response = self.data_stub.UpdateUser(
                request, metadata=self._get_auth_metadata(), timeout=10
            )

            if response.success:
                return {
                    "success": True,
                    "message": response.message,
                    "user": {
                        "user_id": response.user.user_id,
                        "username": response.user.username,
                        "email": response.user.email,
                        "full_name": response.user.full_name,
                        "role": response.user.role,
                    },
                }
            return {"success": False, "message": response.message}
        except grpc.RpcError as e:
            return {
                "success": False,
                "message": f"RPC Error: {e.code().name} - {e.details()}",
            }

    def delete_user(self, user_id: str) -> dict:
        """Delete a user (admin only)."""
        try:
            request = self.pb2.DeleteUserRequest(user_id=user_id)
            response = self.data_stub.DeleteUser(
                request, metadata=self._get_auth_metadata(), timeout=10
            )
            return {"success": response.success, "message": response.message}
        except grpc.RpcError as e:
            return {
                "success": False,
                "message": f"RPC Error: {e.code().name} - {e.details()}",
            }

    def stream_users(
        self, page: int = 1, page_size: int = 10, search_query: str = ""
    ):
        """Stream users via server-side streaming RPC."""
        try:
            request = self.pb2.ListUsersRequest(
                page=page, page_size=page_size, search_query=search_query
            )
            response_stream = self.data_stub.StreamUsers(
                request, metadata=self._get_auth_metadata(), timeout=30
            )

            for response in response_stream:
                yield {
                    "success": response.success,
                    "user": {
                        "user_id": response.user.user_id,
                        "username": response.user.username,
                        "email": response.user.email,
                        "full_name": response.user.full_name,
                        "role": response.user.role,
                    },
                }
        except grpc.RpcError as e:
            yield {
                "success": False,
                "message": f"RPC Error: {e.code().name} - {e.details()}",
            }


