# Demo / Test Script
# ============================================================


def run_demo():
    """Run a demonstration of the gRPC client against the server."""
    import json

    def pretty_print(label, data):
        print(f"\n{'=' * 60}")
        print(f"  {label}")
        print(f"{'=' * 60}")
        print(json.dumps(data, indent=2, default=str))

    print("\n" + "=" * 60)
    print("  gRPC Microservice Demo Client")
    print("=" * 60)

    with UserServiceClient("localhost", 50051) as client:
        # 1. Register a new user
        result = client.register(
            username="new_user",
            email="newuser@example.com",
            password="securepass123",
            full_name="New User",
        )
        pretty_print("1. Register New User", result)

        # 2. Login as admin
        result = client.login("admin", "admin123")
        pretty_print("2. Login as Admin", result)

        # 3. Validate token
        result = client.validate_token()
        pretty_print("3. Validate Token", result)

        # 4. List all users
        result = client.list_users(page=1, page_size=10)
        pretty_print("4. List All Users", result)

        # 5. Search users
        result = client.list_users(search_query="john")
        pretty_print("5. Search Users (query='john')", result)

        # 6. Get specific user (using first user from list)
        if result.get("users"):
            user_id = result["users"][0]["user_id"]
            result = client.get_user(user_id)
            pretty_print(f"6. Get User by ID ({user_id[:8]}...)", result)

        # 7. Update user
        if result.get("user"):
            user_id = result["user"]["user_id"]
            update_result = client.update_user(
                user_id=user_id,
                email="updated@example.com",
                full_name="Updated Name",
            )
            pretty_print(f"7. Update User ({user_id[:8]}...)", update_result)

        # 8. Stream users
        print(f"\n{'=' * 60}")
        print("  8. Stream Users")
        print(f"{'=' * 60}")
        for user_data in client.stream_users(page=1, page_size=5):
            print(f"  Streamed: {json.dumps(user_data, indent=4)}")

        # 9. Delete user (admin operation)
        all_users = client.list_users()
        if all_users.get("users"):
            # Find a non-admin user to delete
            target = next(
                (u for u in all_users["users"] if u["role"] != "admin"),
                None,
            )
            if target:
                result = client.delete_user(target["user_id"])
                pretty_print(
                    f"9. Delete User '{target['username']}'", result
                )

        # 10. Login failure test
        result = client.login("nonexistent", "wrongpass")
        pretty_print("10. Login Failure Test", result)

        # 11. Logout
        client.login("admin", "admin123")  # Re-login first
        result = client.logout()
        pretty_print("11. Logout", result)

        # 12. Access after logout (should fail)
        result = client.list_users()
        pretty_print("12. Access After Logout (should show auth error)", result)


