    parser = argparse.ArgumentParser(
        description="gRPC User Microservice - Server & Client"
    )
    parser.add_argument(
        "mode",
        choices=["server", "client", "demo", "generate"],
        help="Run mode: 'server' to start the gRPC server, "
        "'client'/'demo' to run the demo client, "
        "'generate' to generate proto files only",
    )
    parser.add_argument(
        "--port",
        type=int,
        default=50051,
        help="Port number (default: 50051)",
    )
    parser.add_argument(
        "--host",
        type=str,
        default="localhost",
        help="Host for client connection (default: localhost)",
    )

    args = parser.parse_args()

    if args.mode == "generate":
        generate_proto_files()
        print("Proto files generated successfully!")

    elif args.mode == "server":
        serve(port=args.port)

    elif args.mode in ("client", "demo"):
        run_demo()